  ('judicial-57112235-moex-00637', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人入監時，欠缺下列那項應備文件應拒絕收監？', '["指揮書", "裁判書", "身分證", "指紋卡與人相表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00638', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關遴選受刑人從事「戒護監外作業」及從事「自主監外作業」條件，下列敘述何者錯誤？', '["遴選從事戒護監外作業或自主監外作業者，均需最近6個月內無妨害監獄秩序或安全之行為而受 懲罰", "遴選從事戒護監外作業需在監執行逾1個月，但從事自主監外作業條件者需於本監執行已逾2個月", "拘役或易服勞役之受刑人均不得遴選從事自主監外作業，亦不得從事戒護監外作業", "犯刑法第161條所列之罪不得從事監外作業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00639', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關罪刑法定原則的內涵，下列何者不屬之？', '["信賴原則", "禁止類推適用", "禁止習慣法適用", "罪刑明確性原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00640', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '若行為後，刑法沒收之規定有修正，有關沒收之適用，下列敘述何者正確？', '["從行為時法", "從裁判時法", "從行為時法，但修法後之規定有利於行為人，則從裁判時法", "從裁判時法，但修法後之規定更不利於行為人，則從行為時法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00641', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '廚師甲為了獲取廚師乙所研發的某種食材秘方，將乙強行關在某間屋內。甲告知乙，倘若不說出來，就不 讓他離去。乙不得已，只好如實說出。依實務見解，甲之行為應如何論罪？', '["強制罪與剝奪行動自由罪，數罪併罰", "強制罪與剝奪行動自由罪，想像競合", "強制罪吸收剝奪行動自由罪", "剝奪行動自由罪吸收強制罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00642', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲、乙均為黑道大哥，相約談判。談判間，甲見乙觸摸口袋，以為乙要拔槍射殺甲，而出於防衛意思下手 殺乙，致乙死亡。甲主觀認知與客觀事實不一致。此種不一致，學理上稱為何種「錯誤」？', '["構成要件錯誤", "禁止錯誤", "容許構成要件錯誤", "打擊錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00643', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲持槍向乙宅開槍射擊，欲射殺乙，因乙事先走避未遭殺害。有關甲之刑責，依實務見解，下列敘述何者 正確？', '["甲成立殺人既遂罪", "甲成立殺人罪之障礙未遂", "甲成立殺人罪之中止未遂", "甲屬殺人罪之不能未遂而不罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00644', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關中止犯之敘述，下列何者錯誤？', '["中止犯之法律效果為減輕或免除其刑", "須實行中止行為", "中止行為須出於己意", "過失犯亦得適用中止犯之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00645', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲先殺A，A反抗甚鉅，甲之友人乙碰巧經過現場，立即加入甲之殺人行動，雙方基於共同殺A意思，由 乙抓住A而讓甲順利殺害A。甲、乙刑責為何？', '["甲、乙成立殺人既遂罪之共謀共同正犯", "甲、乙成立殺人既遂罪之相續共同正犯", "甲成立殺人既遂罪，乙成立殺人未遂罪", "甲成立殺人既遂罪之正犯，乙成立殺人既遂罪之幫助犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00646', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者非屬刑法上之共犯？', '["教唆犯", "心理幫助犯", "間接正犯", "物理幫助犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
